import React, { useState } from 'react'
import PropTypes from 'prop-types'

import { Button, Dialog, Tooltip } from '/src/components'
import { PlusIcon, MinusIcon, StopIcon } from '@heroicons/react/outline'
import { AdjustmentSlider } from './AdjustmentSlider'

export const Record = ({ onClose, onStart, ...props }) => {
    const [showLearnMore, setShowLearnMore] = useState(false)
    const [quality, setQuality] = useState(80)
    const handleQualityChange = (value) => {
        setQuality(value[0])
    }
    const [rescale, setRescale] = useState(1)
    const handleRescaleChange = (value) => {
        setRescale(value[0])
    }
    const handleToggleLearnMore = () => {
        setShowLearnMore(!showLearnMore)
    }
    const handleClose = () => {
        onClose()
    }
    const controlLabelClasses = 'text-sm font-bold mb-2 inline-block'
    const handleStart = () => {
        onStart({ rescale, quality })
    }
    return (
        <Dialog onClose={handleClose} {...props} className="py-4 overflow-y-auto">
            <Dialog.Overlay className="py-4 overflow-y-auto">
                <Dialog.Content className="p-6 w-full max-w-2xl">
                    <Dialog.Title className="mb-4">Record</Dialog.Title>
                    <p>
                        Record the scene. Store every frame as a <span className="font-bold">.webp</span> image for high
                        quality/size ratio and download the frames in a zip file. Requires browser to have .webp
                        support.
                    </p>
                    <Button
                        variant="outline"
                        size="sm"
                        className="inline-flex items-center"
                        onClick={handleToggleLearnMore}
                    >
                        More Info{' '}
                        {showLearnMore ? (
                            <MinusIcon className="inline h-4 ml-1 active:bg-transparent" />
                        ) : (
                            <PlusIcon className="inline h-4 ml-1 active:bg-transprent" />
                        )}
                    </Button>
                    <div
                        className={`mt-3 p-3 bg-zinc-100 border border-zinc-400 rounded ${
                            showLearnMore ? 'block' : 'hidden'
                        }`}
                    >
                        <p>
                            Recording the canvas as a series of <span className="font-bold">.webp</span> frames enables
                            much more freedom in image quality and frame rate, but another program will be required to
                            sequence the frames into a video.
                        </p>
                        <p>
                            Although <span className="font-bold">.webp</span> is very efficient, it is very memory
                            intensive. At any time,{' '}
                            <span className="font-bold">
                                stop <StopIcon className="inline h-6" />
                            </span>{' '}
                            the recording to download the progress so far. The download preparation can also be time
                            consuming for 100s or 1,000s of MBs.
                        </p>
                        <p>
                            Each frame represents a value of the <code>time</code> variable value found in the fragment
                            shader.
                        </p>
                    </div>
                    <div className="mt-3">
                        <label className={controlLabelClasses}>Quality: {quality}</label>
                        <div className="w-full">
                            <AdjustmentSlider
                                defaultValue={[0.8]}
                                value={[quality]}
                                min={1}
                                max={100}
                                step={1}
                                onValueChange={handleQualityChange}
                            />
                        </div>
                    </div>
                    <div className="mt-3">
                        <label className={controlLabelClasses}>Rescale: &times;{rescale}</label>
                        <p>
                            <span className="italic text-sm text-zinc-500">
                                Increasing canvas size is also an Anti-Alias cheat
                            </span>
                        </p>
                        <div className="w-full">
                            <AdjustmentSlider
                                defaultValue={[1]}
                                value={[rescale]}
                                min={1}
                                max={8}
                                step={1}
                                onValueChange={handleRescaleChange}
                            />
                        </div>
                    </div>
                    <div className="mt-3">
                        <Button variant="contained" onClick={handleStart}>
                            Start
                        </Button>
                    </div>
                </Dialog.Content>
            </Dialog.Overlay>
        </Dialog>
    )
}
Record.propTypes = {
    onStart: PropTypes.func.isRequired,
    onClose: PropTypes.func.isRequired,
}
