export default ({ maxSteps, distanceFieldOcclusionSamples }) =>
    `
/*
Global Definitions Reference
----------------------------
Due to GLSL constraints, some settings live as macro definitions. For example loops cannot use
variables, even uniform variables.
*/
precision highp float;
precision highp int;

//Ray marching settings
#define MAX_STEPS ${maxSteps}

//Distance field ambient occlusion settings
#define OCCLUSION_SAMPLES ${distanceFieldOcclusionSamples}
uniform float occlusionDistance;

#define M_PI 3.1415926535897932384626433832795

//Pixel/Texel position
varying vec2 vUv;

uniform float time;

uniform sampler2D envMap;

//Will only be filled for lighting passes
uniform sampler2D surfaceData;

//The zoom method changes FOV, and pixelScale is 1 / max(width, height). Together, they can be used to determine
//finite difference gradient and hit threshold values more effectively. This is because in perspective projection,
//tan(fov) gives you the edge of the left, top, right, and bottom edges of the image plane.
uniform float pixelScale;
uniform float tanFov;
    `.trim()
