import React from 'react'
import * as SliderPrim from '@radix-ui/react-slider'

const Root = ({ ...props }) => {
    return <SliderPrim.Root className="px-1 flex relative items-center w-full h-5" {...props} />
}

const Track = ({ ...props }) => {
    return (
        <SliderPrim.Track
            className="relative bg-primary-300 dark:bg-primary-900 h-px-slider-track rounded-full grow"
            {...props}
        />
    )
}

const Range = ({ ...props }) => {
    return (
        <SliderPrim.Range
            className="absolute bg-primary-900 dark:bg-primary-50 h-px-slider-track rounded-full"
            {...props}
        />
    )
}

const Thumb = ({ ...props }) => {
    return (
        <SliderPrim.Thumb
            className="block bg-primary-900 dark:bg-primary-50 w-4 h-4 rounded-full outline outline-[6px] outline-transparent hover:bg-primary-600 focus:outline-primary-300/50 dark:hover:bg-primary-200 dark:focus:outline-primary-900/50"
            {...props}
        />
    )
}

export default {
    Root,
    Track,
    Range,
    Thumb,
}
