import React from 'react'
import PropTypes from 'prop-types'
import * as TooltipPrimitive from '@radix-ui/react-tooltip'

const Content = ({ className, ...props }) => (
    <TooltipPrimitive.Content
        className={`border border-neutral-50 shadow-xl bg-white text-black rounded px-4 py-2 ${className ?? ''}`.trim()}
        {...props}
    />
)
Content.propTypes = {
    className: PropTypes.string,
}

const Arrow = ({ className }) => <TooltipPrimitive className={`bg-white ${className ?? ''}`} />
Arrow.propTypes = {
    className: PropTypes.string,
}

const Tooltip = ({ children, ...props }) => <TooltipPrimitive.Root {...props}>{children}</TooltipPrimitive.Root>
Tooltip.propTypes = {
    ...TooltipPrimitive.Root.propTypes,
    children: PropTypes.node,
}

Tooltip.Trigger = TooltipPrimitive.Trigger
Tooltip.Provider = TooltipPrimitive.Provider
Tooltip.Arrow = Arrow
Tooltip.Content = Content

export default Tooltip
